export function surahsForPara(para: number): Surah[] {
  const surahNumbers = PARA_RANGES.filter(r => r.para === para).map(r => r.surah)
  return SURAHS.filter(s => surahNumbers.includes(s.number))
}

export function ayatRangeForParaSurah(para: number, surah: number): { start: number; end: number } | null {
  const r = PARA_RANGES.find(r => r.para === para && r.surah === surah)
  return r ? { start: r.ayatStart, end: r.ayatEnd } : null
}

export function surahName(number: number): string {
  const s = SURAHS.find(s => s.number === number)
  return s ? s.nameEnglish : ''
}
